import{_ as e,o as s,c as o,g as t}from"./chunks/framework.CpTXwe1b.js";const B=JSON.parse('{"title":"情感容器理论","description":"","frontmatter":{"title":"情感容器理论","date":"2015-07-12T00:26:15.176Z","length":"408字","time":"2分钟","aside":false,"hash":740014681},"headers":[],"relativePath":"article/情感容器理论.md","filePath":"article/情感容器理论.md"}'),_={name:"article/情感容器理论.md"},a=t("p",null,"接着前文对爱情的理解，我提出一个情感容器理论。",-1),n=t("p",null,"爱好比是一杯水，它由两部分组成、一是杯中之水，二是盛水之杯。",-1),l=t("p",null,"杯象征着你个人主观印象，你所构造的一个至美的印象，如一件华装，一方宝座，寻觅着它的主人。而水则象征现实存在，你将水灌入杯中，便是这存在慢慢注满杯，或说它的特征慢慢与你理想要求符合匹配的过程。",-1),c=t("p",null,"杯空之时，人的欲望便是填满它。空杯不能解渴，不能给你滋润的感觉。于是你一个对象披上华装，邀他登临宝座。这过程不是一蹴而就的。还如你满心期待一个人往你杯中倒水，你干渴的眼望着不断贮满。心中难耐与狂喜，交织在一起。这便是人们初恋时那绵绵不绝的思念与期冀。",-1),i=t("p",null,"贮满之后的杯，或说稳定下来的爱情，便要开始接受时间的考验。水会陈，味会淡，或说杯会旧，水会蒸发、会渗漏、初恋、势弯感觉不在，无聊与厌烦随之而来。而人们总是对新鲜事物抱有更大的兴趣。因而有些人又会想倒了这杯，再接下一杯。许多人并不真正爱这水，而是贪恋注水的过程，给他愉悦和刺激。",-1),r=t("p",null,"因而婚姻中的人们需要营造距离，以时刻保持新鲜感。以水的自我净化来代替再灌一杯的恼人举动。",-1),d=[a,n,l,c,i,r];function p(h,u,m,f,$,g){return s(),o("div",null,d)}const k=e(_,[["render",p]]);export{B as __pageData,k as default};
